    // User parameters ends
    // Do not modify the parameters beyond this line

    // Width of S_AXI data bus
    parameter integer AXI_DATA_WIDTH = -1,
    // Width of S_AXI address bus
    parameter integer AXI_ADDR_WIDTH = -1,
    // number of registers
    parameter integer NUM_REGS = -1
) (
    NorthcapeRegInterfaceIO.REG_INTERFACE reg_intf,
    Axi5Lite.TO s_axi
);
  `include "axi5_functional_coverage.svh"
  `include "northcape_unread.vh"

  `AXI5_LITE_TEST_DECLARE_COVERAGE_GROUP(s_axi);

  always @(posedge (s_axi.clk_i)) begin
    `AXI5_LITE_TEST_SAMPLE_COVERAGE_GROUP(s_axi);
