  // AXI4LITE signals
  logic [AXI_ADDR_WIDTH-1 : 0] axi_awaddr, last_axi_awaddr;
  logic axi_awready;
  logic axi_wready;
  axi_resp_t axi_bresp;
  logic axi_bvalid;
