  assign register_index_read = axi_araddr[ADDR_LSB+OPT_MEM_ADDR_BITS:ADDR_LSB];

  // Implement memory mapped register select and read logic generation
  // Slave register read enable is asserted when valid address is available
  // and the slave is ready to accept the read address.
  assign slv_reg_rden = axi_arready & s_axi.arvalid & ~axi_rvalid;
  always @(*) begin
    if (register_index_read < NUM_REGS) begin
      reg_data_out = reg_intf.regs_in[register_index_read];
    end else begin
      reg_data_out = 0;
    end
  end

  // Output register or memory read data
  always @(posedge s_axi.clk_i) begin
    if (s_axi.rst_ni == 1'b0) begin
      axi_rdata <= 0;
    end else begin
      // When there is a valid read address (s_axi.arvalid) with 
      // acceptance of read address by the slave (axi_arready), 
      // output the read dada 
      if (slv_reg_rden) begin
        axi_rdata <= reg_data_out;  // register read data
      end
    end
  end

  `NORTHCAPE_UNREAD(s_axi.arprot);
  `NORTHCAPE_UNREAD(s_axi.awprot);
  `NORTHCAPE_UNREAD(reg_intf.clk_i);

endmodule
